+            code: 1003,
+            message: "fields_to_merge_on must contain at least one Airtable field".into(),
+        });
+    }
+
+    let resolved = resolve_fields(table, field_refs)?;
+    Ok(resolved.into_iter().map(|field| field.name).collect())
